export interface AIMessage {
  role: 'user' | 'assistant' | 'function'
  content: string
  functionCall?: {
    name: string
    arguments: Record<string, any>
  }
  timestamp: number
}

export interface AIResponse {
  message: string
  functionCalls?: Array<{
    name: string
    arguments: Record<string, any>
  }>
  needsUserInput?: boolean
}

// Chat history for context
let chatHistory: AIMessage[] = []

/**
 * Send a message to Gemini AI and get response with function calls
 */
export async function sendMessageToAI(
  userMessage: string,
  language: 'en' | 'ta' | 'hi' | 'te' = 'en'
): Promise<AIResponse> {
  ensureFunctionsReady()

  try {
    // Add user message to history
    chatHistory.push({
      role: 'user',
      content: userMessage,
      timestamp: Date.now()
    })

    const languageName =
      language === 'ta' ? 'Tamil' : language === 'hi' ? 'Hindi' : language === 'te' ? 'Telugu' : 'English'

    const systemPrompt =
      'You are a helpful billing assistant for a sales invoice system. ' +
      'You help users create invoices by finding customers, adding items, applying discounts, and generating invoices. ' +
      'Be concise. When the user mentions customer names or item names, call the appropriate functions.'

    // Build conversation context
    const conversationContext = chatHistory
      .slice(-10) // Last 10 messages for context
      .map(msg => `${msg.role}: ${msg.content}`)
      .join('\n')

    // Create prompt with function definitions
    const prompt = `${systemPrompt}

Available functions you can call:
${JSON.stringify(availableFunctions, null, 2)}

Conversation history:
${conversationContext}

User: ${userMessage}

Analyze the user's message and determine:
1. What function(s) need to be called (if any)
2. What parameters to pass to each function
3. A friendly response message in ${languageName}

Respond in JSON format:
{
  "message": "your response message",
  "functionCalls": [
    {
      "name": "functionName",
      "arguments": { "param1": "value1" }
    }
  ]
}

If no function needs to be called, return empty functionCalls array.`

    const callable = httpsCallable(functions!, 'aiGeminiChat')
    const response = await callable({ prompt, model: 'gemini-2.0-flash' })
    const text = (response.data as any)?.text || ''

    // Parse JSON response
    let aiResponse: AIResponse
    try {
      // Extract JSON from markdown code blocks if present
      const jsonMatch = text.match(/```json\\n([\\s\\S]*?)\\n```/) || text.match(/\\{[\\s\\S]*\\}/)
      const jsonText = jsonMatch ? ((jsonMatch as any)[1] || jsonMatch[0]) : text
      aiResponse = JSON.parse(jsonText)
    } catch {
      // If parsing fails, treat as plain text response
      aiResponse = {
        message: text,
        functionCalls: []
      }
    }

    // Add AI response to history
    chatHistory.push({
      role: 'assistant',
      content: aiResponse.message,
      timestamp: Date.now()
    })

    return aiResponse
  } catch (error) {
    console.error('Error calling AI:', error)
    throw error
  }
}

/**
 * Clear chat history
 */
export function clearChatHistory() {
  chatHistory = []
}

/**
 * Get chat history
 */
export function getChatHistory(): AIMessage[] {
  return chatHistory
}

/**
 * Check if AI is enabled for this user in the UI (server still enforces access).
 */
export function isGeminiConfigured(): boolean {
  return isAdminAIUser()
}
